<template><div class="mx-auto max-w-2xl"><UButton :to="`/students/${studentId}`" color="neutral" variant="ghost" icon="i-lucide-arrow-left">Student profile</UButton><UCard class="mt-4"><template #header><div><h2 class="font-semibold">Student portal access</h2><p class="mt-1 text-sm text-slate-500">Create credentials to share privately with the student. An email address is not required.</p></div></template><form class="grid gap-4" @submit.prevent="save"><UFormField label="Portal username" required><UInput v-model="form.username" placeholder="e.g. akshay.patel" required /></UFormField><UFormField label="Temporary password" required><UInput v-model="form.temporaryPassword" type="password" placeholder="At least 8 characters" required /></UFormField><UCheckbox v-model="form.isActive" label="Portal access is active" /><UButton type="submit" :loading="saving">Save portal access</UButton></form></UCard></div></template>
<script setup lang="ts">definePageMeta({ middleware: ['auth', 'admin'] }); const route = useRoute(); const toast = useToast(); const studentId = Number(route.params.id); const saving = ref(false); const form = reactive({ username: '', temporaryPassword: '', isActive: true }); const { data: account } = await useFetch<any>(`/api/students/${studentId}/portal-account`); watchEffect(() => { if (account.value) { form.username = account.value.username; form.isActive = account.value.isActive } }); async function save() { saving.value = true; try { await $fetch(`/api/students/${studentId}/portal-account`, { method: 'POST', body: form }); form.temporaryPassword = ''; toast.add({ color: 'success', title: 'Portal access saved', description: 'Share the username and temporary password with the student.' }) } catch (error: any) { toast.add({ color: 'error', title: 'Could not save portal access', description: error.data?.statusMessage || error.message }) } finally { saving.value = false } }</script>
